import numpy as np

class OneHotEncoder:
    def fit(self, labels: np.ndarray) -> 'OneHotEncoder':
        self.categories_ = np.array(sorted(set(labels)))
        self.cat_to_idx_ = {c: i for i, c in enumerate(self.categories_)}
        return self

    def transform(self, labels: np.ndarray) -> np.ndarray:
        n = len(labels)
        k = len(self.categories_)
        out = np.zeros((n, k), dtype=float)
        for i, label in enumerate(labels):
            if label in self.cat_to_idx_:
                out[i, self.cat_to_idx_[label]] = 1.0
        return out

    def fit_transform(self, labels: np.ndarray) -> np.ndarray:
        return self.fit(labels).transform(labels)
